#!/usr/bin/env node
// Génère une entrée de changelog depuis le diff git de la session (Stop)
import { execSync } from 'child_process';
import { appendFileSync, existsSync } from 'fs';
import { join } from 'path';
import { fileURLToPath } from 'url';

export function run({
  exec,
  append = appendFileSync,
  exists = existsSync,
  projectDir = process.env.CLAUDE_PROJECT_DIR ?? process.cwd(),
  now = () => new Date().toISOString(),
} = {}) {
  const doExec =
    exec ?? ((cmd) => { try { return execSync(cmd, { encoding: 'utf8', timeout: 10_000, cwd: projectDir }).trim(); } catch { return ''; } });

  const branch = doExec('git branch --show-current');
  const diff = doExec('git diff --stat HEAD~1 HEAD 2>/dev/null || git diff --stat HEAD');
  const commits = doExec('git log -5 --pretty="- %s (%h)"');

  if (!diff && !commits) return null;

  const date = now().split('T')[0];
  const entry = [
    `\n## ${date} — Session sur \`${branch || 'main'}\``,
    '',
    commits ? `### Commits\n${commits}` : '',
    diff ? `### Fichiers modifiés\n\`\`\`\n${diff}\n\`\`\`` : '',
  ]
    .filter(Boolean)
    .join('\n');

  const changelogPath = join(projectDir, 'CHANGELOG.md');
  if (!exists(changelogPath)) {
    return { written: false, message: '[session-changelog] CHANGELOG.md absent — entrée ignorée.\n' };
  }

  append(changelogPath, entry + '\n');
  return { written: true, entry, message: '[session-changelog] ✓ Entrée ajoutée dans CHANGELOG.md\n' };
}

/* v8 ignore next 4 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  if (result?.message) process.stderr.write(result.message);
}

#!/usr/bin/env node
// Bloque npm et yarn, impose pnpm pour ce projet Node.js (PreToolUse Bash)
import { readFileSync } from 'fs';
import { fileURLToPath } from 'url';

const FORBIDDEN = [
  { pattern: /(^|[;&|\s])npm(\s|$)/, replacement: 'pnpm' },
  { pattern: /(^|[;&|\s])yarn(\s|$)/, replacement: 'pnpm' },
];

export function run(input) {
  if (input.tool_name !== 'Bash') return null;
  const cmd = input.tool_input?.command ?? '';
  // Supprime le contenu des chaînes entre guillemets pour éviter les faux positifs
  // quand npm/yarn apparaissent comme valeurs d'arguments texte (ex. git commit -m "...npm...",
  // gh pr create --body "...yarn...") tout en continuant à bloquer les vraies invocations
  // de gestionnaire de paquets même après des opérateurs shell (&&, ||, ;).
  const stripped = cmd
    .replace(/"(?:[^"\\]|\\.)*"/g, '""')
    .replace(/'(?:[^'\\]|\\.)*'/g, "''");
  const hit = FORBIDDEN.find(({ pattern }) => pattern.test(stripped));
  return hit
    ? { decision: 'block', reason: `Utiliser '${hit.replacement}' à la place. Ce projet impose pnpm (pas npm ni yarn).` }
    : null;
}

/* v8 ignore next 5 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const input = JSON.parse(readFileSync(0, 'utf8'));
  const result = run(input);
  if (result) process.stdout.write(JSON.stringify(result));
}

#!/usr/bin/env node
// Empêche l'édition de fichiers hors du worktree courant (PreToolUse Write|Edit)
import { readFileSync } from 'fs';
import { execSync } from 'child_process';
import { resolve } from 'path';
import { fileURLToPath } from 'url';

function defaultExec(cmd) {
  return execSync(cmd, { encoding: 'utf8', timeout: 5_000 }).trim();
}

export function run(input, { exec = defaultExec } = {}) {
  const filePath = input.tool_input?.file_path ?? '';
  if (!filePath) return null;

  try {
    const worktreeRoot = exec('git rev-parse --show-toplevel');
    const worktreeLines = exec('git worktree list').split('\n');
    const mainRoot = worktreeLines[0]?.split(/\s+/)[0] ?? '';

    // N'applique le garde que dans un worktree non principal
    if (!mainRoot || worktreeRoot === mainRoot) return null;

    const absFile = resolve(filePath);
    if (!absFile.startsWith(worktreeRoot + '/')) {
      return {
        decision: 'block',
        reason: `Écriture hors du worktree courant (${worktreeRoot}). Vérifiez le chemin cible.`,
      };
    }
  } catch {
    // git absent ou pas dans un repo — laisser passer
  }
