#!/usr/bin/env node
// Bilan qualité complet à la fin d'une session : typecheck + lint + tests (Stop)
import { execSync } from 'child_process';
import { existsSync } from 'fs';
import { join } from 'path';
import { fileURLToPath } from 'url';

export function run({
  exec,
  exists = existsSync,
  projectDir = process.env.CLAUDE_PROJECT_DIR ?? process.cwd(),
} = {}) {
  const doExec =
    exec ?? ((cmd) => execSync(cmd, { cwd: projectDir, stdio: 'pipe', timeout: 60_000 }));

  const messages = [];
  function check(label, cmd) {
    try {
      doExec(cmd);
      messages.push(`[quality-check] ✓ ${label}\n`);
      return true;
    } catch (err) {
      const out = err.stdout?.toString()?.trim() ?? '';
      messages.push(`[quality-check] ✗ ${label}\n${out ? out.slice(-500) + '\n' : ''}`);
      return false;
    }
  }

  const checks = [];
  const hasPkg = exists(join(projectDir, 'package.json'));
  if (hasPkg && exists(join(projectDir, 'tsconfig.json')))
    checks.push(['TypeScript', 'npx --no-install tsc --noEmit']);
  const eslintConfigs = ['eslint.config.js', 'eslint.config.mjs', 'eslint.config.cjs', '.eslintrc.js', '.eslintrc.cjs', '.eslintrc.json', '.eslintrc.yml', '.eslintrc.yaml', '.eslintrc'];
  if (hasPkg && eslintConfigs.some((f) => exists(join(projectDir, f))))
    checks.push(['ESLint', 'npx --no-install eslint --max-warnings=0 .']);
  if (hasPkg)
    checks.push(['Tests', 'pnpm test --run 2>/dev/null || yarn test --run 2>/dev/null || bun test 2>/dev/null || npm test --if-present 2>/dev/null || npx --no-install vitest run 2>/dev/null']);

  const results = checks.map(([label, cmd]) => check(label, cmd));
  const failed = results.filter((r) => !r).length;

  if (failed > 0) messages.push(`[quality-check] ${failed}/${checks.length} vérification(s) échouée(s).\n`);
  else if (checks.length > 0) messages.push('[quality-check] ✓ Tous les contrôles qualité passent.\n');

  return { checks: checks.length, failed, message: messages.join('') };
}

/* v8 ignore next 5 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  process.stderr.write(result.message);
  if (result.failed > 0) process.exit(2);
}

#!/usr/bin/env node
// SessionStart : si la session démarre dans un worktree, copie depuis le dépôt principal
// les fichiers d'environnement et secrets locaux. Deux passes :
//   1. Liste statique de fichiers racine connus (multi-écosystème)
//   2. Scan récursif (find, profondeur 4) pour couvrir les monorepos (apps/web/.env…)
import { execSync } from 'child_process';
import { existsSync, copyFileSync, mkdirSync, readFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

function defaultExec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 10_000 }).trim(); } catch { return ''; }
}

// Fichiers racine copiés explicitement si présents.
// Couvre Node/Bun, Vite, Next.js, CRA, Python dotenv, Ruby on Rails, direnv, Docker Compose.
const ROOT_FILES = [
  // Dotenv standard — tous frameworks JS/TS/Python
  '.env',
  '.env.local',
  '.env.development',
  '.env.development.local',
  '.env.test',
  '.env.test.local',
  '.env.staging',
  '.env.staging.local',
  '.env.production',
  '.env.production.local',
  '.env.override',            // convention docker-compose
  // direnv
  '.envrc',
  // Ruby on Rails master key
  'config/master.key',
]

// Répertoires exclus du scan récursif monorepo.
const SKIP_DIRS = [
  'node_modules', '.git', 'dist', 'build', '.next', 'out',
  'coverage', '.turbo', '.cache', '__pycache__', 'target', '.venv', 'venv',
]

/**
 * Scan récursif des sous-répertoires (profondeur 2–4) pour trouver les fichiers
 * `.env*` et `.envrc` dans les structures monorepo (apps/web/.env, packages/api/.env…).
 * Utilise `find` via execSync. Injecté en dépendance pour rester testable.
 */
function defaultScanEnvFiles(dir) {
  const excludes = SKIP_DIRS.map(d => `-not -path "*/${d}/*"`).join(' ')
  const cmd = `find "${dir}" -mindepth 2 -maxdepth 4 -type f \\( -name ".env" -o -name ".env.*" -o -name ".envrc" \\) ${excludes} 2>/dev/null`
  try {
    const out = execSync(cmd, { encoding: 'utf8', timeout: 10_000 }).trim()
    if (!out) return []
    return out.split('\n').map(abs => abs.slice(dir.length + 1))
  } catch { return [] }
}

export function run({
  exec = defaultExec,
  exists = existsSync,
  copy = copyFileSync,
  mkdir = mkdirSync,
  scanEnvFiles = defaultScanEnvFiles,
} = {}) {
  const worktreeList = exec('git worktree list')
  const mainDir = worktreeList.split('\n')[0]?.split(/\s+/)[0] ?? ''
  const worktreeDir = exec('git rev-parse --show-toplevel')

  if (!mainDir || !worktreeDir || mainDir === worktreeDir) return

  // Fusion liste statique + résultats du scan monorepo (déduplication)
  const candidates = [...ROOT_FILES]
  for (const rel of scanEnvFiles(mainDir)) {
    if (!candidates.includes(rel)) candidates.push(rel)
  }

  for (const rel of candidates) {
    const src = join(mainDir, rel)
    const dst = join(worktreeDir, rel)
    if (exists(src) && !exists(dst)) {
      const dstDir = dirname(dst)
      if (!exists(dstDir)) mkdir(dstDir, { recursive: true })
      copy(src, dst)
      process.stderr.write(`Copié : ${rel} → ${worktreeDir}\n`)
    }
  }
}

/* v8 ignore next 5 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  readFileSync(0, 'utf8')
  run()
  // SessionStart : stdout vide = aucun contexte ajouté.
}

#!/usr/bin/env node
// SessionStart : si la session démarre dans un worktree fraîchement créé (node_modules
// absent), lance l'install des dépendances en process DÉTACHÉ pour ne pas bloquer le
// démarrage de session, puis rend la main immédiatement.
// NB : ce hook NE s'enregistre PAS sur WorktreeCreate — ce dernier remplace la création
// du worktree, exige un chemin absolu sur stdout et ne supporte pas l'exécution async.
import { execSync, spawn } from 'child_process';
import { existsSync, readFileSync } from 'fs';
import { fileURLToPath } from 'url';

/* v8 ignore next 3 */
function defaultExec(cmd, opts = {}) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 10_000, ...opts }).trim(); } catch { return ''; }
}

/* v8 ignore next 8 */
function defaultDetach(cmd, args, cwd) {
  const child = spawn(cmd, args, {
    cwd,
    detached: true,
    stdio: 'ignore',
  });
  child.unref();
}

export function run({
  exec = defaultExec,
  exists = existsSync,
  detach = defaultDetach,
} = {}) {
  const worktreeDir = exec('git rev-parse --show-toplevel');
  if (!worktreeDir) return;

  // Uniquement dans un worktree distinct du dépôt principal.
  const mainDir = exec('git worktree list').split('\n')[0]?.split(/\s+/)[0] ?? '';
  if (!mainDir || mainDir === worktreeDir) return;

  // Rien à faire sans package.json, ou si les deps sont déjà installées.
  if (!exists(`${worktreeDir}/package.json`)) return;
  if (exists(`${worktreeDir}/node_modules`)) return;

  const hasPnpm = exec('which pnpm');
  if (hasPnpm) {
    detach('pnpm', ['install', '--frozen-lockfile', '--ignore-scripts'], worktreeDir);
  } else {
    detach('npm', ['ci', '--ignore-scripts'], worktreeDir);
  }
}

/* v8 ignore next 5 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  readFileSync(0, 'utf8');
  run();
  // SessionStart : pas de stdout obligatoire (install lancé en détaché).
}

#!/usr/bin/env node
// Détecte les fichiers sources modifiés sans test correspondant (Stop)
import { readFileSync, existsSync, writeFileSync, unlinkSync } from 'fs';
import { execSync } from 'child_process';
import { basename } from 'path';
import { fileURLToPath } from 'url';

const pid = process.ppid ?? 'unknown';

function defaultExec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 10_000 }).trim(); } catch { return ''; }
}

export function run({
  exec = defaultExec,
  exists = existsSync,
  readFile = readFileSync,
  writeFile = writeFileSync,
  unlink = unlinkSync,
  counterFile = `/tmp/.claude-missing-tests-count-${pid}`,
  disableFile = `/tmp/.claude-missing-tests-disabled-${pid}`,
} = {}) {
  if (exists(disableFile)) {
    process.stderr.write(`[missing-test-detection] SUSPENDU (≥3 échecs). rm '${disableFile}' pour réactiver.\n`);
    return { exitCode: 0 };
  }

  const base = exec('git merge-base origin/main HEAD');
  const head = exec('git rev-parse HEAD');
  const raw = base && base !== head
    ? exec(`git diff --name-only ${base} HEAD`)
    : exec('git diff --name-only HEAD');

  const missing = [];
  for (const f of raw.split('\n').filter(Boolean)) {
    if (!/^src\/(lib|store|hooks)\/[^/]+\.ts$/.test(f)) continue;
    if (/\.(test|spec)\.ts$/.test(f)) continue; // un fichier de test n'exige pas son propre test
    if (!exists(f)) continue; // fichier supprimé → pas de test requis
    const name = basename(f, '.ts');
    const found = exec(`find src tests -name "${name}.test.ts" -o -name "${name}.spec.ts" 2>/dev/null`);
    if (!found) missing.push(f);
  }

  if (!missing.length) {
    try { unlink(counterFile); } catch {}
    process.stderr.write('[missing-test-detection] ✓ Aucun fichier source sans test détecté.\n');
    return { exitCode: 0 };
  }

  let count = 0;
  try { count = parseInt(readFile(counterFile, 'utf8').trim(), 10) || 0; } catch {}
  count++;
  writeFile(counterFile, String(count));

  let msg = `[FAIL] Tests manquants pour les fichiers modifiés :\n${missing.map(f => `  - ${f}`).join('\n')}\n→ Créer les fichiers de test correspondants.\n`;
  if (count >= 3) {
    writeFile(disableFile, '');
    msg += `[AUTO-DISABLE] hook suspendu après ${count} échecs. rm '${disableFile}' pour réactiver.\n`;
  }

  return { exitCode: 2, message: msg };
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  if (result.message) process.stderr.write(result.message);
  process.exit(result.exitCode);
}

