// Vérifie la coverage ≥80% par fichier .ts/.tsx modifié (Stop)
import { readFileSync, existsSync, writeFileSync, unlinkSync } from 'fs';
import { execSync } from 'child_process';
import { fileURLToPath } from 'url';

const pid = process.ppid ?? 'unknown';

function defaultExec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 10_000 }).trim(); } catch { return ''; }
}

const SKIP = /^src\/(types|constants|router|main)\//;

export function run({
  exec = defaultExec,
  exists = existsSync,
  readFile = readFileSync,
  writeFile = writeFileSync,
  unlink = unlinkSync,
  cwd = process.cwd(),
  counterFile = `/tmp/.claude-per-cov-count-${pid}`,
  disableFile = `/tmp/.claude-per-cov-disabled-${pid}`,
  covJson = './coverage/coverage-summary.json',
} = {}) {
  if (exists(disableFile)) {
    process.stderr.write(`[per-file-coverage] SUSPENDU (≥3 échecs). rm '${disableFile}' pour réactiver.\n`);
    return { exitCode: 0 };
  }

  if (!exists(covJson)) return { exitCode: 0 };

  const base = exec('git merge-base origin/main HEAD');
  const head = exec('git rev-parse HEAD');
  const raw = base && base !== head
    ? exec(`git diff --name-only ${base} HEAD`)
    : exec('git diff --name-only HEAD');

  let coverage;
  try { coverage = JSON.parse(readFile(covJson, 'utf8')); } catch { return { exitCode: 0 }; }

  const lowCov = [];
  for (const f of raw.split('\n').filter(Boolean)) {
    if (!/^src\/.*\.tsx?$/.test(f) || SKIP.test(f)) continue;
    const pct = coverage[`${cwd}/${f}`]?.lines?.pct;
    if (pct != null && pct < 80) lowCov.push({ f, pct });
  }

  if (!lowCov.length) {
    try { unlink(counterFile); } catch {}
    return { exitCode: 0 };
  }

  let count = 0;
  try { count = parseInt(readFile(counterFile, 'utf8').trim(), 10) || 0; } catch {}
  count++;
  writeFile(counterFile, String(count));

  let msg = `[FAIL] Coverage < 80% pour les fichiers modifiés :\n${lowCov.map(({ f, pct }) => `  - ${f}: ${Math.round(pct)}%`).join('\n')}\n→ Ajouter des tests pour atteindre le seuil.\n`;
  if (count >= 3) {
    writeFile(disableFile, '');
    msg += `[AUTO-DISABLE] hook suspendu après ${count} échecs. rm '${disableFile}' pour réactiver.\n`;
  }

  return { exitCode: 2, message: msg };
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  if (result.message) process.stdout.write(result.message);
  process.exit(result.exitCode);
}

#!/usr/bin/env node
// Lint ESLint chaque fichier .js/.ts modifié depuis la merge base (Stop)
import { readFileSync, existsSync, writeFileSync, unlinkSync } from 'fs';
import { execSync } from 'child_process';
import { fileURLToPath } from 'url';

const pid = process.ppid ?? 'unknown';

function defaultExec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 10_000 }).trim(); } catch { return ''; }
}

// Signatures indiquant qu'ESLint n'a pas pu DÉMARRER (config absente, mauvaise version,
// binaire introuvable) — à distinguer d'une vraie violation de lint. Dans ce cas on traite
// ESLint comme un outil indisponible et on ne fait PAS échouer le hook (évite les faux positifs).
const ESLINT_UNAVAILABLE =
  /Oops! Something went wrong|could ?n'?t find an? eslint\.config|eslint\.config\.\(|migration guide|Cannot find module|could not determine executable|command not found|ENOENT/i;

export function isEslintUnavailable(output) {
  return !output || ESLINT_UNAVAILABLE.test(output);
}

// Retourne null si le fichier passe ESLint (ou si ESLint est indisponible), sinon la sortie d'erreur.
/* v8 ignore next 14 */
function defaultLint(file) {
  try {
    execSync(`npx --no-install eslint --max-warnings=0 "${file}"`, {
      encoding: 'utf8',
      stdio: 'pipe',
      timeout: 15_000,
    });
    return null;
  } catch (err) {
    const out = `${err.stdout ?? ''}\n${err.stderr ?? ''}`.trim();
    if (isEslintUnavailable(out)) return null; // ESLint n'a pas démarré → skip, pas un échec
    return out || 'lint error';
  }
}

export function run({
  exec = defaultExec,
  lint = defaultLint,
  exists = existsSync,
  readFile = readFileSync,
  writeFile = writeFileSync,
  unlink = unlinkSync,
  counterFile = `/tmp/.claude-per-lint-count-${pid}`,
  disableFile = `/tmp/.claude-per-lint-disabled-${pid}`,
} = {}) {
  if (exists(disableFile)) {
    process.stderr.write(`[per-file-lint] SUSPENDU (≥3 échecs). rm '${disableFile}' pour réactiver.\n`);
    return { exitCode: 0 };
  }

  const base = exec('git merge-base origin/main HEAD');
  const head = exec('git rev-parse HEAD');
  const raw = base && base !== head
    ? exec(`git diff --name-only ${base} HEAD`)
    : exec('git diff --name-only HEAD');

  const failed = [];
  let checked = 0;
  for (const f of raw.split('\n').filter(Boolean)) {
    if (!/\.[cm]?[jt]sx?$/.test(f)) continue;
    if (!exists(f)) continue; // fichier supprimé → rien à linter
    checked++;
    const out = lint(f);
    if (out) failed.push({ f, out });
  }

  if (!failed.length) {
    try { unlink(counterFile); } catch {}
    return { exitCode: 0, message: checked ? `✓ ESLint: no issues (${checked} file${checked > 1 ? 's' : ''})\n` : '✓ ESLint: nothing to check\n' };
  }

  let count = 0;
  try { count = parseInt(readFile(counterFile, 'utf8').trim(), 10) || 0; } catch {}
  count++;
  writeFile(counterFile, String(count));

  let msg = `[FAIL] ESLint signale des problèmes sur les fichiers modifiés :\n${failed.map(({ f }) => `  - ${f}`).join('\n')}\n→ Corriger les erreurs de lint (ou \`eslint --fix\`).\n`;
  if (count >= 3) {
    writeFile(disableFile, '');
    msg += `[AUTO-DISABLE] hook suspendu après ${count} échecs. rm '${disableFile}' pour réactiver.\n`;
  }

  return { exitCode: 2, message: msg };
}

/* v8 ignore next 5 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  if (result.message) process.stderr.write(result.message);
  process.exit(result.exitCode);
}

#!/usr/bin/env node
// Auto-désactive les hooks Stop qui ont échoué ≥ N fois de suite (Stop)
import { readFileSync, existsSync, readdirSync } from 'fs';
import { join } from 'path';
import { fileURLToPath } from 'url';

const MAX_FAILURES = 3;

export function run({
  exists = existsSync,
  readdir = readdirSync,
  readFile = readFileSync,
  counterDir = '/tmp/claude-hook-counters',
} = {}) {
  if (!exists(counterDir)) return null;

  try {
    const counters = readdir(counterDir).filter((f) => f.endsWith('.counter'));
    const toDisable = counters
      .map((f) => {
        try {
          const count = parseInt(readFile(join(counterDir, f), 'utf8').trim(), 10);
          return count >= MAX_FAILURES ? f.replace('.counter', '') : null;
        } catch {
          return null;
        }
      })
      .filter(Boolean);

    if (!toDisable.length) return null;

    const message =
      `[session-dedup] Hooks à désactiver (${MAX_FAILURES}+ échecs) : ${toDisable.join(', ')}\n` +
      '[session-dedup] Supprimez les fichiers /tmp/claude-hook-counters/*.counter pour réactiver.\n';
    return { toDisable, message };
  } catch {
    // Erreur de lecture — ignorer silencieusement
    return null;
  }
}

/* v8 ignore next 4 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  if (result?.message) process.stderr.write(result.message);
}

#!/usr/bin/env node
// Valide la cohérence des fichiers de traduction (Stop)
import { readFileSync, existsSync } from 'fs';
import { execSync } from 'child_process';
import { join } from 'path';
import { fileURLToPath } from 'url';

export function run({
  exec,
  readFile = readFileSync,
  projectDir = process.env.CLAUDE_PROJECT_DIR ?? process.cwd(),
} = {}) {
  const doExec =
    exec ?? ((cmd) => execSync(cmd, { encoding: 'utf8', timeout: 5_000, cwd: projectDir }).trim());

  // Cherche les fichiers de traduction JSON (ex: locales/fr.json, messages/en.json)
  const i18nFiles = doExec('find . -path ./node_modules -prune -o -name "*.json" -print')
    .split('\n')
    .filter((f) => /\/(locales?|messages?|i18n)\//i.test(f) && f.endsWith('.json'));

  if (i18nFiles.length < 2) return null;

  // Groupe par répertoire et vérifie la cohérence des clés
  const byDir = {};
  for (const f of i18nFiles) {
    const dir = f.split('/').slice(0, -1).join('/');
    byDir[dir] ??= [];
    byDir[dir].push(f);
  }

  const issues = [];
  for (const [, files] of Object.entries(byDir)) {
    if (files.length < 2) continue;
    const parsed = files
      .map((f) => {
        try { return { f, keys: new Set(Object.keys(JSON.parse(readFile(join(projectDir, f), 'utf8')))) }; } catch { return null; }
      })
      .filter(Boolean);

    const allKeys = new Set(parsed.flatMap((p) => [...p.keys]));
    for (const { f, keys } of parsed) {
      const missing = [...allKeys].filter((k) => !keys.has(k));
      if (missing.length > 0)
        issues.push(`${f} manque ${missing.length} clé(s) : ${missing.slice(0, 5).join(', ')}${missing.length > 5 ? '…' : ''}`);
    }
  }

  const message =
    issues.length > 0
      ? `[i18n-validation] Incohérences détectées :\n${issues.map((i) => `  - ${i}`).join('\n')}\n`
      : '[i18n-validation] ✓ Fichiers de traduction cohérents.\n';

  return { issues, message };
}

/* v8 ignore next 4 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  if (result) process.stderr.write(result.message);
}

